// /frontend/src/components/Radar.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";
import { MapContainer, TileLayer } from "react-leaflet";
import "leaflet/dist/leaflet.css";

function clamp(n, min, max) { return Math.max(min, Math.min(max, n)); }

export default function Radar({
  center = [33.7490, -84.3880],
  zoom = 5,
  height = 260,
  className = "",
  refreshSeconds = 60,        // check for a new frame every 60s
}) {
  const alive = useRef(true);
  const [visible, setVisible] = useState(false);
  const [frameTime, setFrameTime] = useState(null);
  const [tilesLoaded, setTilesLoaded] = useState(false);
  const [tileError, setTileError] = useState(false);

  // Guard center and zoom
  const safeCenter = useMemo(() => {
    let [lat, lon] = Array.isArray(center) ? center : [33.7490, -84.3880];
    lat = Number.isFinite(lat) ? clamp(lat, -85, 85) : 33.7490;
    lon = Number.isFinite(lon) ? clamp(lon, -180, 180) : -84.3880;
    return [lat, lon];
  }, [center]);

  const safeZoom = useMemo(() => (Number.isFinite(zoom) ? clamp(zoom, 3, 10) : 5), [zoom]);

  // Only activate when visible on screen
  const hostRef = useRef(null);
  useEffect(() => {
    const el = hostRef.current;
    if (!el) return;
    const io = new IntersectionObserver(
      (entries) => setVisible(entries[0]?.isIntersecting ?? false),
      { root: null, threshold: 0.05 }
    );
    io.observe(el);
    return () => io.disconnect();
  }, []);

  // Fetch latest frame time (once on mount + periodic while visible)
  useEffect(() => {
    alive.current = true;

    async function fetchTime() {
      try {
        const r = await fetch("https://api.rainviewer.com/public/weather-maps.json", { cache: "no-store" });
        const j = await r.json();
        // use the newest *past* frame (always available)
        const latest = j?.radar?.past?.at(-1)?.time ?? j?.radar?.nowcast?.[0]?.time ?? null;
        if (alive.current && latest) {
          setFrameTime((prev) => (prev !== latest ? latest : prev));
          setTileError(false);
        }
      } catch {
        // soft-fail; we'll retry on next tick
      }
    }

    // initial grab
    fetchTime();

    // periodic refresh while visible
    let id;
    if (visible) {
      id = setInterval(fetchTime, Math.max(15, refreshSeconds) * 1000);
    }
    return () => {
      alive.current = false;
      if (id) clearInterval(id);
    };
  }, [visible, refreshSeconds]);

  // Fallback to current 10â€‘min bucket if API fails (prevents {time} template errors)
  const effectiveTime = useMemo(() => {
    if (typeof frameTime === "number") return frameTime;
    return Math.floor(Date.now() / (10 * 60 * 1000)) * (10 * 60); // seconds
  }, [frameTime]);

  const radarUrl = useMemo(() =>
    `https://tilecache.rainviewer.com/v2/radar/${effectiveTime}/256/{z}/{x}/{y}/2/1_1.png`
  , [effectiveTime]);

  // Force a clean remount when center/zoom change to avoid Leaflet state glitches
  const mapKey = `${safeCenter[0].toFixed(3)},${safeCenter[1].toFixed(3)}@${safeZoom}`;

  // If not visible on screen, render a lightweight placeholder (no map)
  if (!visible) {
    return (
      <div ref={hostRef} className={`w-full ${className}`} style={{ height, borderRadius: 16, overflow: "hidden" }}>
        <div className="w-full h-full flex items-center justify-center text-xs"
             style={{ background: "rgba(0,0,0,0.06)" }}>
          Radar paused (off-screen)
        </div>
      </div>
    );
  }

  return (
    <div ref={hostRef} className={`relative w-full ${className}`} style={{ height }}>
      <MapContainer
        key={mapKey}
        center={safeCenter}
        zoom={safeZoom}
        minZoom={3}
        maxZoom={10}
        style={{ width: "100%", height: "100%", borderRadius: 16, overflow: "hidden" }}
        scrollWheelZoom={false}
        dragging={false}
        doubleClickZoom={false}
        boxZoom={false}
        keyboard={false}
        zoomControl={false}
        attributionControl={false}
        zoomAnimation={false}
        fadeAnimation={false}
        markerZoomAnimation={false}
        inertia={false}
        preferCanvas={true}
      >
        {/* faint base so it never looks blank */}
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          opacity={0.3}
        />
        {/* radar (precip + snow) */}
        <TileLayer
          url={radarUrl}
          opacity={0.9}
          eventHandlers={{
            tileload: () => setTilesLoaded(true),
            load: () => setTilesLoaded(true),
            tileerror: () => setTileError(true),
          }}
          updateWhenIdle={true}
          updateWhenZooming={false}
          keepBuffer={2}
          detectRetina={false}
        />
      </MapContainer>

      {/* subtle status */}
      <div
        className="pointer-events-none absolute right-2 bottom-2 text-xs text-white"
        style={{ backdropFilter: "blur(6px)", background: "rgba(0,0,0,0.35)", padding: "4px 8px", borderRadius: 8 }}
      >
        Live radar â€˘ scroll-safe
      </div>

      {/* loading / empty state */}
      {(!tilesLoaded || tileError) && (
        <div className="pointer-events-none absolute inset-0 flex items-center justify-center">
          <div style={{
            padding: "6px 10px",
            borderRadius: 10,
            fontSize: 12,
            color: "white",
            backdropFilter: "blur(6px)",
            background: "rgba(0,0,0,0.35)"
          }}>
            {tileError ? "Radar tiles failedâ€”retryingâ€¦" : "Loading latest radarâ€¦"}
          </div>
        </div>
      )}
    </div>
  );
}
